// URL generada para tu cuenta dwpgncjgn y carpeta Productos
export const URL_CARPETA_IMAGENES = "https://res.cloudinary.com/dwpgncjgn/image/upload/f_auto,q_auto/v1/Productos/";

export const DICCIONARIO_PRODUCTOS = {
  'Almacén': ['Aceite de Girasol', 'Aceite de Oliva', 'Arroz Blanco', 'Arroz Integral', 'Fideos Tallarín', 'Fideos Tirabuzón', 'Harina 000', 'Harina 0000', 'Azúcar Blanca', 'Sal Fina', 'Galletitas Dulces', 'Galletitas Saladas'],
  'Lácteos': ['Leche Entera', 'Leche Descremada', 'Yogur Frutilla', 'Yogur Vainilla', 'Queso Crema', 'Manteca', 'Dulce de Leche'],
  'Bebidas': ['Agua Mineral', 'Agua con Gas', 'Gaseosa Cola', 'Gaseosa Lima Limón', 'Cerveza Rubia', 'Jugo de Naranja', 'Vino Tinto', 'Vino Blanco'],
  'Limpieza': ['Detergente', 'Lavandina', 'Jabón en Polvo', 'Jabón Líquido', 'Desinfectante', 'Suavizante', 'Limpiador de Pisos'],
  'Perfumería': ['Shampoo', 'Acondicionador', 'Jabón de Tocador', 'Desodorante Hombre', 'Desodorante Mujer', 'Pasta Dental'],
  'Carnicería': ['Asado', 'Vacío', 'Pollo Entero', 'Pechuga de Pollo', 'Carne Picada', 'Milanesas de Carne', 'Milanesas de Pollo']
};

export const generarNombreImagen = (tipo, marca, contenido) => {
  // Combinamos los campos
  const nombreCompleto = `${tipo} ${marca} ${contenido}`;
  
  return nombreCompleto
    .toLowerCase()
    .trim()
    // 1. Elimina tildes y diéresis (Ñoquis -> Noquis)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    // 2. Cambia puntos y comas por guiones (1.5kg -> 1-5kg)
    // Esto evita que el navegador piense que ".5kg" es una extensión de archivo
    .replace(/[.,]/g, '-')
    // 3. Quita cualquier cosa que no sea letra, número, espacio o guion
    .replace(/[^a-z0-9\s-]/g, "")
    // 4. Convierte espacios en guiones
    .replace(/\s+/g, '-')
    // 5. Colapsa guiones múltiples (--- -> -)
    .replace(/-+/g, '-')
    // 6. Quita guiones al principio o al final
    .replace(/^-+|-+$/g, "");
};
